const today = $('Query Today\'s Stats').first().json;
const week = $('Query This Week').first().json;
const payments = $('Query Payments').first().json;

const date = new Date().toLocaleDateString('en-KE', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

// Find most popular service
const services = [
  { name: 'CV Writing', count: today.cv_count || 0, revenue: today.cv_revenue || 0 },
  { name: 'Gov Services', count: today.gov_count || 0, revenue: today.gov_revenue || 0 },
  { name: 'Translation', count: today.translate_count || 0, revenue: today.translate_revenue || 0 },
  { name: 'Printing', count: today.print_count || 0, revenue: today.print_revenue || 0 },
  { name: 'Data Bundles', count: today.data_count || 0, revenue: today.data_revenue || 0 },
  { name: 'Typing', count: today.typing_count || 0, revenue: today.typing_revenue || 0 }
];
services.sort((a, b) => b.count - a.count);
const topService = services[0];

const report = `📊 AEGO CYBER CAFE — DAILY REPORT
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📅 ${date}

💰 TODAY'S REVENUE
   Total: KES ${(today.total_revenue || 0).toLocaleString()}
   Payments: ${payments.payment_count || 0} successful

📋 TODAY'S REQUESTS
   Total: ${today.total_requests || 0}
   Completed: ${today.completed_count || 0}
   Pending: ${today.pending_count || 0}

🏆 SERVICES BREAKDOWN
   CV Writing:    ${today.cv_count || 0} requests — KES ${(today.cv_revenue || 0).toLocaleString()}
   Gov Services:  ${today.gov_count || 0} requests — KES ${(today.gov_revenue || 0).toLocaleString()}
   Translation:   ${today.translate_count || 0} requests — KES ${(today.translate_revenue || 0).toLocaleString()}
   Printing:      ${today.print_count || 0} requests — KES ${(today.print_revenue || 0).toLocaleString()}
   Data Bundles:  ${today.data_count || 0} requests — KES ${(today.data_revenue || 0).toLocaleString()}
   Typing:        ${today.typing_count || 0} requests — KES ${(today.typing_revenue || 0).toLocaleString()}

📈 THIS WEEK
   Total Requests: ${week.total_requests || 0}
   Total Revenue: KES ${(week.total_revenue || 0).toLocaleString()}

⭐ Most Popular: ${topService.name} (${topService.count} requests)

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
Aego Cyber Cafe • Nyatike, Migori`;

return [{
  json: {
    report: report,
    stats: {
      today_revenue: today.total_revenue || 0,
      today_requests: today.total_requests || 0,
      week_revenue: week.total_revenue || 0,
      week_requests: week.total_requests || 0,
      top_service: topService.name
    }
  }
}];
